// PREPARE — validate + parse + compute reminder offsets + select stage.
// PROVENANCE: ported from upstream Apps Script src/Code.gs @ fce2513 (onMilestoneFormSubmit + helpers). See PROVENANCE.md.
const input = $input.first().json;
const data = input.data || {};
const config = input.config || {};
const REQUIRED = ['專案編號','專案名稱','日期類型','日期','負責人','負責人Email'];
for (const f of REQUIRED) if (!data[f] || String(data[f]).trim()==='') throw new Error('缺少必填欄位：'+f);
for (const c of ['CONTROL_SHEET_ID','CALENDAR_ID','TIMEZONE']) if (!config[c]) throw new Error('Missing config: '+c);

function formatTs(date, tz, fmt) {
  const parts = new Intl.DateTimeFormat('en-CA', { timeZone: tz, year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit', second:'2-digit', hour12: false }).formatToParts(date).reduce((o,p)=>(o[p.type]=p.value,o),{});
  const HH = parts.hour === '24' ? '00' : parts.hour;
  return fmt.replace('yyyy', parts.year).replace('MM', parts.month).replace('dd', parts.day).replace('HH', HH).replace('mm', parts.minute).replace('ss', parts.second);
}
function parseDate(v) { if (!v) return null; if (v instanceof Date) return new Date(v.getTime()); const d=new Date(String(v).trim().replace(/-/g,'/')); return isNaN(d.getTime())?null:d; }
function offsetDate(v, days) { const d=parseDate(v); if(!d) return null; d.setDate(d.getDate()+Number(days||0)); return d; }
function toIsoDate(d) { if(!d) return null; return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }
function fmtSheet(v) { const d=parseDate(v); if(!d) return String(v||''); return d.getFullYear()+'/'+String(d.getMonth()+1).padStart(2,'0')+'/'+String(d.getDate()).padStart(2,'0'); }
function isAffirmative(v) { const t=String(v||'').trim(); return t===''||t==='是'||t.toLowerCase()==='yes'||t.toLowerCase()==='true'; }
function determineStage(t) { /* <- Code.gs:L1000-1018 determineTaskStageByDateType */
  t=String(t||'').trim();
  if (['報名開始日','報名截止日','資料回收期限'].includes(t)) return '表單收件';
  if (['採購期限','經費核銷期限'].includes(t)) return '經費';
  if (['正式活動日期','活動前檢查日','校內協調會','第一次會議'].includes(t)) return '執行';
  if (['照片與成果資料回收日','成果報告初稿期限','成果送出期限'].includes(t)) return '成果';
  if (t==='結案檢討日') return '結案';
  return '其他';
}
function parseReminderOptions(v) {
  const t=String(v||'').trim(); if(!t) return [];
  const m={'當天提醒':0,'前1天提醒':-1,'前3天提醒':-3,'前7天提醒':-7,'前14天提醒':-14}; /* <- Code.gs:L1021-1031 parseReminderOptions */
  return t.split(/[,，\n]/).map(s=>s.trim()).filter(s=>s&&m[s]!==undefined).map(s=>({label:s,days:m[s]}));
}

const now = new Date();
const tz = config.TIMEZONE;
const createdAt = formatTs(now, tz, 'yyyy/MM/dd HH:mm');
const recordId = 'M-' + formatTs(now, tz, 'yyyyMMdd-HHmmss');
const taskId = 'M' + formatTs(now, tz, 'MMddHHmmss');
const milestoneDate = parseDate(data['日期']);
if (!milestoneDate) throw new Error('日期無法解析：'+data['日期']);
let reminders = parseReminderOptions(data['提醒設定']);
if (!reminders.length) reminders=[{label:'當天提醒',days:0}];
let earliest = milestoneDate;
for (const r of reminders) { const c=offsetDate(milestoneDate, r.days); if (c && c<earliest) earliest=c; }

return [{
  json: {
    config, data, createdAt, recordId, taskId,
    milestoneDateIso: toIsoDate(milestoneDate),
    milestoneDateText: fmtSheet(milestoneDate),
    reminderEarliestText: fmtSheet(earliest),
    reminders,
    writeToTaskSheet: isAffirmative(data['是否寫入待辦追蹤表']),
    createCalendarReminders: isAffirmative(data['是否建立Calendar提醒']),
    stage: determineStage(data['日期類型'])
  }
}];

const prep = $('Prepare').first().json;
const row = $input.first().json;
if (!row || (!row['專案編號'] && !row.專案編號)) throw new Error('找不到專案編號：'+prep.data['專案編號']);
function parseSpreadsheetIdFromUrl(url) {
  const text = String(url||'').trim(); if(!text) return '';
  let m = text.match(/\/d\/([a-zA-Z0-9_-]+)/); if (m) return m[1];
  m = text.match(/[?&]id=([a-zA-Z0-9_-]+)/);  if (m) return m[1];
  m = text.match(/^([a-zA-Z0-9_-]{20,})$/);    return m ? m[1] : '';
}
const project = {
  projectCode: row['專案編號'],
  projectName: row['專案名稱'] || prep.data['專案名稱'],
  folderUrl: row['Drive資料夾連結'] || '',
  projectDocUrl: row['專案紀錄Docs連結'] || '',
  taskSheetUrl: row['待辦追蹤表連結'] || '',
  taskSheetId: parseSpreadsheetIdFromUrl(row['待辦追蹤表連結'] || ''),
  checklistSheetUrl: row['成果檢核表連結'] || '',
  owner: row['承辦人'] || '',
  ownerEmail: row['承辦人Email'] || '',
  status: row['專案狀態'] || ''
};
return [{ json: { ...prep, project } }];

const prep = $input.first().json;
const row = {
  '任務編號': prep.taskId,
  '階段': prep.stage,
  '任務名稱': '【' + prep.data['日期類型'] + '】' + (prep.project.projectName || prep.data['專案名稱'] || ''),
  '任務說明': ['階段日期：'+prep.milestoneDateText,'提醒設定：'+(prep.data['提醒設定']||'當天提醒'),'說明：'+(prep.data['說明']||'')].join('\n'),
  '負責人': prep.data['負責人'] || '',
  '協助單位': '',
  '期限': prep.milestoneDateText,
  '提醒日期': prep.reminderEarliestText,
  '狀態': '未開始',
  '需要附件': '否',
  '附件位置': '',
  '備註': prep.data['備註'] || ''
};
return [{ json: { _carry: prep, ...row } }];

const prep = $input.first().json;
const { reminders, milestoneDateIso, project, data, config } = prep;
function off(iso, days) { const d=new Date(iso); if (isNaN(d.getTime())) return null; d.setDate(d.getDate()+Number(days||0)); return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }
const description = [
  '專案編號：'+(project.projectCode||data['專案編號']||''),
  '專案名稱：'+(project.projectName||data['專案名稱']||''),
  '日期類型：'+(data['日期類型']||''),
  '日期：'+prep.milestoneDateText,
  '負責人：'+(data['負責人']||''),
  '負責人Email：'+(data['負責人Email']||''),
  '說明：'+(data['說明']||''),
  '',
  'Drive 專案資料夾：'+(project.folderUrl||''),
  '待辦追蹤表：'+(project.taskSheetUrl||''),
  '',
  '提醒：正式公告、經費核銷與成果送出仍需人工確認。'
].join('\n');
return reminders.map(r => {
  const iso = off(milestoneDateIso, r.days);
  const title = `【${r.label}｜${data['日期類型']||'階段日期'}】${project.projectName||data['專案名稱']||''}`;
  return { json: { ...prep, _eventTitle: title, _eventDate: iso, _eventDescription: description, _calendarId: config.CALENDAR_ID } };
});

const all = $input.all();
const prep = $('After task branch').first().json;
const eventIds = all.map(it => it.json.id).filter(Boolean);
return [{ json: { ...prep, calendarEventIds: eventIds } }];

